// Separate definition (recommended)
struct Date {
    int day, month, year;
};

struct Student {
    char name[50];
    int  roll;
    struct Date dob;   // nested struct
};

int main() {
    struct Student s;
    s.roll        = 101;
    s.dob.day     = 15;   // nested access
    s.dob.month   = 8;
    s.dob.year    = 2000;

    printf("%d/%d/%d\n",
           s.dob.day, s.dob.month, s.dob.year);
    // Output: 15/8/2000
    return 0;
}

